import FloatingLabel from 'react-bootstrap/FloatingLabel';
import Form from 'react-bootstrap/Form';

function FormFloatingTextareaExample() {
  return (
    <>
      <FloatingLabel controlId="floatingTextarea" label="Full Name" className="justify-content-md-center mb-2">
        <Form.Control as="textarea" placeholder="Enter your full name" />
      </FloatingLabel>
      <FloatingLabel controlId="floatingTextarea2" label="Email">
        <Form.Control
          as="textarea" placeholder="Enter your email" 
        />
      </FloatingLabel>
      <FloatingLabel controlId="floatingTextarea" label="Phone No" className="justify-content-md-center mb-2">
        <Form.Control as="textarea" placeholder="Enter your full name" />
      </FloatingLabel>
      <FloatingLabel controlId="floatingTextarea" label="Full Name" className="justify-content-md-center mb-2">
        <Form.Control as="textarea" placeholder="Enter your full name" />
      </FloatingLabel>
    </>
  );
}

export default FormFloatingTextareaExample;
